import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatWithFirstRecordAsHeaderTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withFirstRecordAsHeader();

        // The returned CSVFormat should not be the same instance
        assertNotSame(format, result);

        // The returned CSVFormat should have header set (non-null)
        assertNotNull(result.getHeader());

        // The returned CSVFormat should skip header record
        assertTrue(result.getSkipHeaderRecord());

        // The returned CSVFormat should preserve other DEFAULT properties
        assertEquals(format.getDelimiter(), result.getDelimiter());
        assertEquals(format.getQuoteCharacter(), result.getQuoteCharacter());
        assertEquals(format.getIgnoreEmptyLines(), result.getIgnoreEmptyLines());
        assertEquals(format.getRecordSeparator(), result.getRecordSeparator());
    }
}
